import{bQ as a,aL as i,u as e,G as n}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"08｜InnoDB 存储引擎","description":"","frontmatter":{},"headers":[],"relativePath":"04.MySQL/08-InnoDB存储引擎.md","filePath":"04.MySQL/08-InnoDB存储引擎.md","lastUpdated":null}'),o={name:"04.MySQL/08-InnoDB存储引擎.md"};function t(l,s,d,p,h,r){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="_08-innodb-存储引擎" tabindex="-1">08｜InnoDB 存储引擎 <a class="header-anchor" href="#_08-innodb-存储引擎" aria-label="Permalink to &quot;08｜InnoDB 存储引擎&quot;">​</a></h1><p>前面建表时都写了 <code>ENGINE=InnoDB</code>。为什么用 InnoDB？它和别的存储引擎有什么区别？为什么 MySQL 断电重启后数据不丢、为什么能回滚事务、为什么有行锁——这些都和 InnoDB 的内部机制有关。</p><p>本篇讲 InnoDB 存储引擎的几个核心：Buffer Pool（内存缓存）、Redo Log（崩溃恢复）、Undo Log（回滚）、表空间。理解了这些，出问题时能判断该往哪个方向查。</p><h2 id="一、buffer-pool-mysql-的工作台" tabindex="-1">一、Buffer Pool：MySQL 的工作台 <a class="header-anchor" href="#一、buffer-pool-mysql-的工作台" aria-label="Permalink to &quot;一、Buffer Pool：MySQL 的工作台&quot;">​</a></h2><p>InnoDB 读写数据不直接操作磁盘——太慢了。它先把数据从磁盘读到内存里的一块区域，在内存里改，改完再刷回磁盘。这块内存就是 <strong>Buffer Pool</strong>。</p><p>可以理解成工作台。磁盘像书架，书（数据）平时在书架上。要看一本书，先从书架拿到工作台上。工作台越大，能同时摊开的书越多。工作台太小，看几页就要放回书架、再拿新的，大部分时间花在&quot;来回拿&quot;而不是&quot;看&quot;上。</p><h3 id="工作台够不够大" tabindex="-1">工作台够不够大 <a class="header-anchor" href="#工作台够不够大" aria-label="Permalink to &quot;工作台够不够大&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GLOBAL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> STATUS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Innodb_buffer_pool_read%&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>两个指标：</p><ul><li><code>Innodb_buffer_pool_read_requests</code> — 总共要从 Buffer Pool 读多少次（逻辑读）</li><li><code>Innodb_buffer_pool_reads</code> — 其中多少次 Buffer Pool 没有，得去磁盘拿（物理读）</li></ul><p>命中率：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1 - Innodb_buffer_pool_reads / Innodb_buffer_pool_read_requests) × 100%</span></span></code></pre></div><p>99% 以上才算健康。低于 99%，说明工作台太小，大部分时间花在从磁盘搬数据上。</p><h3 id="调多大" tabindex="-1">调多大 <a class="header-anchor" href="#调多大" aria-label="Permalink to &quot;调多大&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW VARIABLES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;innodb_buffer_pool_size&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>机器只跑 MySQL 给到物理内存 70%-80%。机器还跑别的服务要留一些。8.0+ 支持在线调，不用重启：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> GLOBAL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> innodb_buffer_pool_size </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 17179869184</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 16G</span></span></code></pre></div><h3 id="出问题时的表现" tabindex="-1">出问题时的表现 <a class="header-anchor" href="#出问题时的表现" aria-label="Permalink to &quot;出问题时的表现&quot;">​</a></h3><p>查询本身不慢（EXPLAIN 走索引了），但就是响应慢——大概率 Buffer Pool 太小，频繁去磁盘读。但注意：EXPLAIN 显示 <code>type = ALL</code>（全表扫），先解决索引问题，不是 Buffer Pool。<strong>先看索引，再看 Buffer Pool，顺序别反。</strong></p><h2 id="二、redo-log-干完活的底单" tabindex="-1">二、Redo Log：干完活的底单 <a class="header-anchor" href="#二、redo-log-干完活的底单" aria-label="Permalink to &quot;二、Redo Log：干完活的底单&quot;">​</a></h2><p>Buffer Pool 在内存里改数据快，但有个问题：<strong>机器突然断电，内存里的数据全丢了怎么办？</strong></p><p>InnoDB 靠 <strong>redo log</strong> 解决。改数据时，InnoDB 先把&quot;改了哪几页数据&quot;记到 redo log（只追加写的文件），再改内存里的 Buffer Pool。</p><p>理解成快递底单：寄包裹时快递员先让你填一张底单（日志），底单落袋了，包裹后面慢慢送。万一包裹丢了，凭底单可以重新发一份。</p><p><strong>redo log 的作用是 MySQL 崩溃后，通过重放 redo log 把已提交但没写回磁盘的数据恢复回来。</strong> 这个过程叫 crash recovery，重启时自动做，不用人工干预。</p><h3 id="一个关键参数" tabindex="-1">一个关键参数 <a class="header-anchor" href="#一个关键参数" aria-label="Permalink to &quot;一个关键参数&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW VARIABLES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;innodb_flush_log_at_trx_commit&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>默认 <code>1</code>，每次事务提交都把 redo log 刷到磁盘。最安全——但每次提交都要写磁盘，写入量大时对 IO 有压力。改成 <code>2</code> 表示每秒刷一次，OS 崩溃时可能丢 1 秒数据。核心业务库保持 <code>1</code>，日志类、可接受少量丢数据的库才考虑调低。</p><h3 id="redo-log-和-binlog-的区别" tabindex="-1">redo log 和 binlog 的区别 <a class="header-anchor" href="#redo-log-和-binlog-的区别" aria-label="Permalink to &quot;redo log 和 binlog 的区别&quot;">​</a></h3><p>这两个经常搞混，职责完全不同：</p><table tabindex="0"><thead><tr><th></th><th>redo log</th><th>binlog</th></tr></thead><tbody><tr><td>谁管的</td><td>InnoDB 引擎层</td><td>MySQL Server 层</td></tr><tr><td>记什么</td><td>哪个数据页被改了</td><td>哪条 SQL 或哪行变更被提交</td></tr><tr><td>干什么用</td><td>崩溃恢复</td><td>主从复制、时间点恢复</td></tr><tr><td>要不要人工管</td><td>不用，自动</td><td>要，备份和清理策略</td></tr></tbody></table><p><strong>崩溃恢复靠 redo，复制和恢复靠 binlog。</strong> redo 是快递员的底单（保证包裹不丢），binlog 是你的寄件记录（可以查某天寄了什么）。</p><h2 id="三、undo-log-后悔药" tabindex="-1">三、Undo Log：后悔药 <a class="header-anchor" href="#三、undo-log-后悔药" aria-label="Permalink to &quot;三、Undo Log：后悔药&quot;">​</a></h2><p>开了个事务，先插了一条数据，又觉得不对想回滚。InnoDB 怎么知道插入之前是什么状态？靠 <strong>undo log</strong>。</p><p>undo log 记录的是修改前的老数据。插入前记下&quot;这里原来是空的&quot;，更新前记下&quot;原来是什么值&quot;。回滚时按 undo log 把数据改回去。</p><p>undo log 还有一个重要用途——MVCC（多版本并发控制）。一个事务在改数据，另一个事务同时读这条数据，读到的应该是改之前的值（没提交的不能读）。undo log 存了老版本，让读操作能拿到一致性的快照，不用等写操作完成。这就是为什么 InnoDB 读写不互相阻塞（行锁不阻塞普通读）。</p><h3 id="undo-log-和长事务" tabindex="-1">undo log 和长事务 <a class="header-anchor" href="#undo-log-和长事务" aria-label="Permalink to &quot;undo log 和长事务&quot;">​</a></h3><p>undo log 要保留到事务结束（回滚或提交后才能清理）。如果一个事务开着一直不提交（长事务），它对应的 undo log 一直占着空间，表空间越来越大，性能下降。</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 看有没有跑很久的事务</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> information_schema</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">innodb_trx</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> trx_started </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ASC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>看到跑了几个小时的事务要排查——多半是应用开了连接没提交（忘了 commit）或连接池泄漏。</p><h2 id="四、表空间" tabindex="-1">四、表空间 <a class="header-anchor" href="#四、表空间" aria-label="Permalink to &quot;四、表空间&quot;">​</a></h2><p>InnoDB 的数据存在表空间里。每张表的数据存哪：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW VARIABLES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;innodb_file_per_table&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p><code>ON</code>（8.0 默认）：每张表单独一个 <code>.ibd</code> 文件，存在 <code>datadir/库名/表名.ibd</code>。管理和备份方便，删表直接删文件释放空间。</p><p><code>OFF</code>：所有表共享一个系统表空间（<code>ibdata1</code>）。删表不释放空间，文件越来越大。不推荐。</p><p>8.0 默认每表一个文件，不用管这个参数。但要记着数据存在哪——排查磁盘满、要单独备份某张表时知道去哪找。</p><h2 id="五、这几个机制怎么配合" tabindex="-1">五、这几个机制怎么配合 <a class="header-anchor" href="#五、这几个机制怎么配合" aria-label="Permalink to &quot;五、这几个机制怎么配合&quot;">​</a></h2><p>一条 <code>UPDATE</code> 从执行到完成，InnoDB 内部走了一遍：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 从磁盘读数据页到 Buffer Pool（如果不在内存）</span></span>
<span class="line"><span>2. 记 undo log（记下改之前的值，用于回滚和 MVCC）</span></span>
<span class="line"><span>3. 改 Buffer Pool 里的数据页</span></span>
<span class="line"><span>4. 记 redo log（记下改了哪个页，用于崩溃恢复）</span></span>
<span class="line"><span>5. 记 binlog（Server 层记变更，用于复制和恢复）</span></span>
<span class="line"><span>6. 提交事务，redo log 刷盘（双 1 配置下）</span></span></code></pre></div><p>后面 Buffer Pool 里的脏页（改了但没刷盘的页）会在后台慢慢刷回磁盘表空间。断电了不怕——redo log 在磁盘上，重启时重放恢复。</p><p>理解这个流程，就能解释很多现象：为什么断电不丢已提交的数据（redo log）、为什么能回滚（undo log）、为什么长事务有问题（undo log 不清理）、为什么改数据要先读进内存（Buffer Pool）。</p><h2 id="存储引擎之后" tabindex="-1">存储引擎之后 <a class="header-anchor" href="#存储引擎之后" aria-label="Permalink to &quot;存储引擎之后&quot;">​</a></h2><p>知道了 InnoDB 怎么存数据、怎么恢复、怎么回滚。但多个事务同时操作时怎么不互相干扰——事务和锁——下一篇讲。这是&quot;为什么有锁等待、为什么会死锁&quot;的根因。</p>`,52)])])}const g=a(o,[["render",t]]);export{c as __pageData,g as default};
